export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:50。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從卸貨口出來。側台的燈光打在臉上，他瞇了一下眼睛。從黑暗裡走出來的瞬間，世界突然變亮了、變吵了、變近了。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在前面。他走得不快，但每一步都踩在舞台組該走的動線上——靠牆、低頭、手裡拿著一捲膠帶裝作在幹活。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言跟在他後面。不近。不遠。三步的距離。他走在側台暗處——燈架背後、布幕旁邊、攝影機拍不到的死角。這些死角是韓越下午就確認過的。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:50。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和每一輪一樣。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他離開了。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他離開了。22:50。「後台清場確認」。和前七輪一樣。消失在走廊盡頭。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他離開了。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）目標——許星棠。真相機。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）接下來他會做兩件事。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）切斷韓越的通行卡。清空後台半封閉設備通道。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看向舞台側門的方向。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越站在走廊裡。靠牆。手插在口袋裡。木楔還在門縫底下——下午就塞好的。這個木楔讓門無法完全鎖死，就算電子門禁啟動，物理上門仍然可以推開。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的身體僵了一下。口袋裡有什麼東西震動了一下。然後停了。韓越從口袋裡抽出一張卡。舞台組臨時通行證。藍底白字。他低頭看了一眼。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "卡的感應晶片面朝上。上面沒有燈。沒有反應。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的嘴壓成一條線。他沒有去門旁的感應器貼卡。他知道沒用。上一輪他試過兩次。兩次亮紅。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯又來了。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:52。通行卡被切。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和上一輪一樣。和上上一輪一樣。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但韓越沒有慌。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把卡收回口袋。轉身。往舞台側門的方向走。不是往門禁感應器走——是往公共區域走。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不硬闖。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）上一輪他試過硬闖。被校安攔下。浪費了三分鐘。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次——他用另一條路。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越走到舞台側門。推開。門外是禮堂後方的公共走廊——家長和學生來來往往，閉幕倒數的氣氛讓所有人都擠在這附近。韓越走進人群裡。他的舞台組通行證還掛在脖子上——通行卡被切了，但通行證本身還在。在人群裡，沒有人會查他的卡。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他穿過公共走廊。繞到設備通道的另一頭。那邊有一扇側門——側門開著。木楔還在。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他推開門。木楔還在。門開了。", background: Background.Chapter_8_Ch8_Act15_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯退路保住了。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔切了通行卡。但韓越不靠卡了。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他用舞台動線和公共區域保護退路。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和計畫一樣。", background: Background.Chapter_8_Ch8_Act15_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:55。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言移到了直播控制區附近的暗處。一排機櫃的背面。燈架和線纜在頭頂交錯，遮住了天花板的攝影機。他蹲在那裡。能看見設備通道的入口。能看見直播控制台的側面。能看見——", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在直播控制台旁邊。相機掛在脖子上。背帶纏在手腕上。她的臉很白，嘴唇壓成一條線，但她站著。兩隻腳踩在地上。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回頭。她站著。等。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）相機在她身上。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）備份線在控制台裡。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越在走廊那頭。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三個人。三個位置。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）星棠在直播備份線旁邊。帶真相機和最後素材。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我在側台暗處。帶備援短片。等邵叔誤判完成後現身。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越在走廊。保持退路。阻止門被完全鎖死。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三個人。不聚在一起。避免被一次抓住。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看見了林主任。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一頭。林主任站在門禁讀卡器旁邊。手裡捏著手機。手機貼著耳朵。他在聽。他的臉在螢光燈下是灰色的。額頭上有汗。眼鏡歪了一點。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他在害怕。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的聲音從手機裡傳出來——顧言聽不清每一個字，但斷斷續續地聽見了。「⋯⋯設備通道⋯⋯門關上⋯⋯清場。」", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔在命令他。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）關掉設備通道的門。配合清場。和每一輪一樣。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任掛了電話。他把手機收進口袋。然後他看向門禁讀卡器。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手伸向口袋裡的門禁卡。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手指碰到了卡片。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——停了。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他慢了。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和前幾輪不一樣。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前七輪，林主任會毫不猶豫地刷卡。關門。配合清場。每一次都是。他是被邵叔握住把柄的人。他不敢不配合。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這一次——他的手停在口袋裡。卡片沒有掏出來。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）為什麼。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）基座。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）19:30 拆展的時候，星棠和韓越拍了底板資料。林主任不知道被拍了——但他看見韓越接近過基座。他比前幾輪更緊張。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他看見邵叔已經失控了。直播馬上開始。家長和媒體比前幾輪更近。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在害怕。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是怕邵叔。是怕自己成為下一個被丟掉的人。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的手從口袋裡抽出來。空的。沒有卡片。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在那裡。沒有刷卡。沒有關門。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不是正義。是恐懼。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低頭看了一眼手機。螢幕暗了。他沒有回撥給邵叔。他把手機收進口袋裡，往走廊另一頭走。往公共區域走。往人群走。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他走了。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）門沒有關。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）設備通道是開的。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔會自己來。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:57。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言蹲在機櫃背後。雨聲從禮堂外面傳進來。閉幕倒數的準備聲越來越近。主持人的聲音從舞台方向傳過來——在測麥克風。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見許星棠站在直播控制台旁邊。她沒有動。她的手放在控制台的邊緣。備份線的接口在控制台右側——韓越確認過的位置。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）23:00。她只需要把備份線的素材從「閉幕回顧」切換到「證據包」。不是駭入。是替換。她本來就是紀錄小組成員。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:57。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）還有三分鐘。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔會在 22:58 開設備通道的門。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和每一輪一樣。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會穿著雨衣。他會用那種溫和的、像父親一樣的聲音說——", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）星棠，把相機交給我。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但這一次——", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）星棠不會被拖進去。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她會站在門檻上。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一步後退是死角。一步往前是鏡頭能拍到的邊界。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不退。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後——", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）23:00。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）直播切換。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）證據出去。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我現身。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）最後三分鐘。", background: Background.Chapter_8_Ch8_Act15_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:58。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從走廊那頭傳來。穩。踏實。不急不慢。是那種十年來在鳴海高中說一不二的人的腳步聲。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔出現在設備通道的入口。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他穿著深色雨衣。和每一輪一樣。雨衣的帽沿壓著。他的臉在螢光燈下看起來很平。很穩。像一個來處理例行公事的人。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了許星棠。", background: Background.Chapter_8_Ch8_Act15_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走向她。", background: Background.Chapter_8_Ch8_Act15_S1 },
];
